redis_client = redis.Redis(host='localhost', port=6379, db=0, decode_responses=True)

# Rate limiting configuration
RATE_LIMIT_WINDOW = 60  # seconds
RATE_LIMIT_MAX_REQUESTS = 30  # requests per window
RATE_LIMIT_BURST_WINDOW = 3600  # 1 hour
RATE_LIMIT_BURST_MAX = 500  # max requests per hour

# Abuse detection thresholds
SUSPICIOUS_PATTERN_THRESHOLD = 100  # identical queries in short time
SUSPICIOUS_PATTERN_WINDOW = 300  # 5 minutes

def get_client_identifier(request):
    """Get unique client identifier from request"""
    # Use IP address and User-Agent for identification
    ip = request.headers.get('X-Forwarded-For', request.remote_addr)
    if ip:
        ip = ip.split(',')[0].strip()
    user_agent = request.headers.get('User-Agent', '')
    identifier = f"{ip}:{hashlib.md5(user_agent.encode()).hexdigest()[:8]}"
    return identifier

def rate_limit(f):
    """Rate limiting decorator with multiple tiers"""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        client_id = get_client_identifier(request)
        current_time = int(time.time())
        
        # Per-minute rate limit
        minute_key = f"rate_limit:minute:{client_id}:{current_time // RATE_LIMIT_WINDOW}"
        minute_count = redis_client.incr(minute_key)
        if minute_count == 1:
            redis_client.expire(minute_key, RATE_LIMIT_WINDOW * 2)
        
        if minute_count > RATE_LIMIT_MAX_REQUESTS:
            # Log potential abuse
            abuse_key = f"abuse:rate_limit:{client_id}"
            redis_client.incr(abuse_key)
            redis_client.expire(abuse_key, 86400)  # 24 hours
            
            return jsonify({
                'error': 'Rate limit exceeded',
                'message': 'Too many requests. Please try again later.'
            }), 429
        
        # Hourly burst protection
        hour_key = f"rate_limit:hour:{client_id}:{current_time // RATE_LIMIT_BURST_WINDOW}"
        hour_count = redis_client.incr(hour_key)
        if hour_count == 1:
            redis_client.expire(hour_key, RATE_LIMIT_BURST_WINDOW * 2)
        
        if hour_count > RATE_LIMIT_BURST_MAX:
            abuse_key = f"abuse:burst:{client_id}"
            redis_client.incr(abuse_key)
            redis_client.expire(abuse_key, 86400)
            
            return jsonify({
                'error': 'Rate limit exceeded',
                'message': 'Too many requests. Please try again later.'
            }), 429
        
        # Add rate limit headers
        response = f(*args, **kwargs)
        if isinstance(response, tuple):
            response_obj, status_code = response[0], response[1]
        else:
            response_obj, status_code = response, 200
        
        if hasattr(response_obj, 'headers'):
            response_obj.headers['X-RateLimit-Limit'] = str(RATE_LIMIT_MAX_REQUESTS)
            response_obj.headers['X-RateLimit-Remaining'] = str(max(0, RATE_LIMIT_MAX_REQUESTS - minute_count))
            response_obj.headers['X-RateLimit-Reset'] = str((current_time // RATE_LIMIT_WINDOW + 1) * RATE_LIMIT_WINDOW)
        
        return response_obj, status_code
    
    return decorated_function

def detect_suspicious_patterns(client_id, query):
    """Detect suspicious search patterns that might indicate scraping or abuse"""
    current_time = int(time.time())
    
    # Track query patterns
    query_hash = hashlib.md5(query.encode()).hexdigest()
    pattern_key = f"pattern:{client_id}:{query_hash}:{current_time // SUSPICIOUS_PATTERN_WINDOW}"
    
    pattern_count = redis_client.incr(pattern_key)
    if pattern_count == 1:
        redis_client.expire(pattern_key, SUSPICIOUS_PATTERN_WINDOW * 2)
    
    if pattern_count > SUSPICIOUS_PATTERN_THRESHOLD:
        # Log suspicious activity
        suspicious_key = f"suspicious:{client_id}"
        redis_client.setex(suspicious_key, 3600, "1")
        return True
    
    # Track unique queries to detect enumeration
    unique_queries_key = f"unique_queries:{client_id}:{current_time // 300}"
    redis_client.sadd(unique_queries_key, query_hash)
    redis_client.expire(unique_queries_key, 600)
    
    unique_count = redis_client.scard(unique_queries_key)
    if unique_count > 50:  # Too many unique queries in 5 minutes
        suspicious_key = f"suspicious:{client_id}"
        redis_client.setex(suspicious_key, 3600, "1")
        return True
    
    return False

def is_client_blocked(client_id):
    """Check if client is blocked due to abuse"""
    blocked_key = f"blocked:{client_id}"
    return redis_client.exists(blocked_key)

def sanitize_query(query):
    """Sanitize and validate search query"""
    if not query:
        return None
    
    # Remove excessive whitespace
    query = ' '.join(query.split())
    
    # Limit query length
    if len(query) > 200:
        query = query[:200]
    
    # Basic validation
    if len(query) < 2:
        return None
    
    return query

